require('dotenv').config();
const { Pool } = require('pg');

const pool = new Pool({
  user: process.env.PG_USER,
  host: process.env.PG_HOST,
  database: process.env.PG_DATABASE,
  password: process.env.PG_PASSWORD,
  port: process.env.PG_PORT,
});

// CREATE
const createItem = async (item) => {
  const result = await pool.query('INSERT INTO tablename(columns) VALUES($1) RETURNING *', [item]);
  return result.rows[0];
}

// READ
const getItems = async () => {
  const result = await pool.query('SELECT * FROM tablename');
  return result.rows;
}

// UPDATE
const updateItem = async (id, item) => {
  const result = await pool.query('UPDATE tablename SET columns=$1 WHERE id=2 RETURNING *', [item]);
  return result.rows[0];
}

// DELETE
const deleteItem = async (id) => {
  const result = await pool.query('DELETE FROM tablename WHERE id=$1', [id]);
  return result.rowCount; // Return the number of rows deleted
}